# Base geometry module with abstract shapes and interfaces
@abstract
class Shape:
    """Abstract base class for all geometric shapes."""
    name: str

    def __init__(self, name: str):
        self.name = name

    @virtual
    def area(self) -> float:
        return 0.0

    @virtual
    def perimeter(self) -> float:
        return 0.0

    @virtual
    def __str__(self) -> str:
        return "Shape: " + self.name

interface IDrawable:
    """Interface for drawable objects."""
    def draw(self) -> str: ...

    def get_color(self) -> str: ...

interface ITransformable:
    """Interface for transformable shapes."""
    def scale(self, factor: float) -> None: ...

def calculate_total_area(shapes: list[Shape]) -> float:
    """Calculate total area of all shapes in the list."""
    total: float = 0.0
    for s in shapes:
        total += s.area()
    return total

def find_largest_shape(shapes: list[Shape]) -> Shape:
    """Find the shape with the largest area."""
    largest: Shape = shapes[0]
    for s in shapes:
        if s.area() > largest.area():
            largest = s
    return largest

