# Concrete shape implementations with cross-module inheritance
from geometry_base import Shape, IDrawable, ITransformable
from shape_types import Color, Point, Dimension, color_to_string

# Module-level helper function (was nested inside Triangle.perimeter)
def distance(a: Point, b: Point) -> float:
    """Calculate Euclidean distance between two points."""
    dx: float = b.x - a.x
    dy: float = b.y - a.y
    return pow(dx * dx + dy * dy, 0.5)

class Circle(Shape, IDrawable):
    """Circle shape - inherits from Shape, implements IDrawable."""
    center: Point
    radius: float
    color: Color

    def __init__(self, name: str, center: Point, radius: float, color: Color):
        super().__init__(name)
        self.center = center
        self.radius = radius
        self.color = color

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    @override
    def draw(self) -> str:
        return "Drawing circle '" + self.name + "' with radius " + str(self.radius)

    @override
    def get_color(self) -> str:
        return color_to_string(self.color)

    @override
    def scale(self, factor: float) -> None:
        self.radius *= factor

    @override
    def __str__(self) -> str:
        return "Circle(" + self.name + ", r=" + str(self.radius) + ")"

class Rectangle(Shape, IDrawable, ITransformable):
    """Rectangle shape - inherits from Shape, implements both interfaces."""
    top_left: Point
    dim: Dimension

    def __init__(self, name: str, top_left: Point, width: float, height: float):
        super().__init__(name)
        self.top_left = top_left
        self.dim = Dimension(width, height)

    @override
    def area(self) -> float:
        return self.dim.area()

    @override
    def perimeter(self) -> float:
        return 2.0 * (self.dim.width + self.dim.height)

    @override
    def draw(self) -> str:
        return "Drawing rectangle '" + self.name + "' " + str(self.dim.width) + "x" + str(self.dim.height)

    @override
    def get_color(self) -> str:
        return "Black"

    @override
    def scale(self, factor: float) -> None:
        self.dim = Dimension(self.dim.width * factor, self.dim.height * factor)

    @override
    def __str__(self) -> str:
        return "Rectangle(" + self.name + ", " + str(self.dim.width) + "x" + str(self.dim.height) + ")"

class Triangle(Shape):
    """Triangle shape - simple polygon."""
    p1: Point
    p2: Point
    p3: Point

    def __init__(self, name: str, p1: Point, p2: Point, p3: Point):
        super().__init__(name)
        self.p1 = p1
        self.p2 = p2
        self.p3 = p3

    @override
    def area(self) -> float:
        # Using shoelace formula for triangle area
        return abs((self.p1.x * (self.p2.y - self.p3.y) + self.p2.x * (self.p3.y - self.p1.y) + self.p3.x * (self.p1.y - self.p2.y)) / 2.0)

    @override
    def perimeter(self) -> float:
        # Uses module-level distance function
        return distance(self.p1, self.p2) + distance(self.p2, self.p3) + distance(self.p3, self.p1)

    @override
    def __str__(self) -> str:
        return "Triangle(" + self.name + ")"
